def main() -> None:
    nodes = list(
        KnowledgeNode.objects.filter(
            node_type="recurso",
            parent__parent__semantic_id="MAT.NUM.B0204",
        ).order_by("parent__order", "order", "semantic_id")
    )
    ids = [node.semantic_id for node in nodes]
    missing = set(ids) - set(SPECS)
    extra = set(SPECS) - set(ids)
    if len(nodes) != 93 or missing or extra:
        raise RuntimeError(
            f"B0204 inconsistente: nodes={len(nodes)} missing={missing} extra={extra}"
        )

    for node in nodes:
        base.safe_write_yaml(
            base.CONTENT_DIR / base.yaml_filename(node.semantic_id),
            build_content(node.semantic_id, node.name),
        )

    all_meta = {
        sid: {
            "definition": SPECS[sid]["definition"],
            "example": SPECS[sid]["example"],
            "fact": SPECS[sid]["fact"],
        }
        for sid in ids
    }
    groups = [ids[i : i + 5] for i in range(0, len(ids), 5)]
    for index, group in enumerate(groups, start=1):
        rows = []
        for sid in group:
            node = next(n for n in nodes if n.semantic_id == sid)
            rows.extend(
                base.make_exercises(sid, node.name, node.competencia, all_meta)
            )
        base.write_jsonl(
            base.EXERCISES_DIR / f"mat-num-reales-banco-gen-{index}.jsonl", rows
        )
    print(f"B0204 generado: {len(nodes)} YAML y {len(groups)} JSONL.")


if __name__ == "__main__":
    main()
